var urlApi = "http://127.0.0.1:8000/eventos"

// imagenes por defecto para los eventos iniciales
var imagenesDefecto = {
    1: "data:image/jpeg;base64,",
    2: "data:image/jpeg;base64,",
    3: "data:image/jpeg;base64,"
}

// ---- funciones de imagenes ----

function obtenerImagenes() {
    var guardadas = localStorage.getItem("imagenes")
    if (guardadas == null) {
        return {}
    }
    return JSON.parse(guardadas)
}

function guardarImagenEvento(id, base64) {
    var imagenes = obtenerImagenes()
    imagenes[id] = base64
    localStorage.setItem("imagenes", JSON.stringify(imagenes))
}

function obtenerImagenEvento(id) {
    var imagenes = obtenerImagenes()
    if (imagenes[id] != null) {
        return imagenes[id]
    }
    if (imagenesDefecto[id] != null) {
        return imagenesDefecto[id]
    }
    return null
}

// ---- funciones de favoritos ----

function obtenerFavoritos() {
    var guardados = localStorage.getItem("favoritos")
    if (guardados == null) {
        return []
    }
    return JSON.parse(guardados)
}

function guardarFavoritos(lista) {
    localStorage.setItem("favoritos", JSON.stringify(lista))
}

function estaEnFavoritos(id) {
    var favoritos = obtenerFavoritos()
    var encontrado = false
    for (var i = 0; i < favoritos.length; i++) {
        if (favoritos[i].id == id) {
            encontrado = true
        }
    }
    return encontrado
}

function toggleFavorito(id, nombre, artista, lugar, precio) {
    var favoritos = obtenerFavoritos()

    if (estaEnFavoritos(id)) {
        var nuevaLista = []
        for (var i = 0; i < favoritos.length; i++) {
            if (favoritos[i].id != id) {
                nuevaLista.push(favoritos[i])
            }
        }
        guardarFavoritos(nuevaLista)
        mostrarToast("Quitado de favoritos")
    } else {
        var evento = {
            id: id,
            nombre: nombre,
            artista: artista,
            lugar: lugar,
            precio: precio
        }
        favoritos.push(evento)
        guardarFavoritos(favoritos)
        mostrarToast("Agregado a favoritos!")
    }

    var contenedorFav = document.getElementById("lista-favoritos")
    if (contenedorFav != null) {
        mostrarFavoritos()
    }

    var boton = document.getElementById("fav-btn-" + id)
    if (boton != null) {
        if (estaEnFavoritos(id)) {
            boton.textContent = "★ Guardado"
            boton.classList.add("activo")
        } else {
            boton.textContent = "☆ Favorito"
            boton.classList.remove("activo")
        }
    }
}

// ---- mostrar toast ----

function mostrarToast(mensaje) {
    var toast = document.getElementById("toast")
    toast.textContent = mensaje
    toast.classList.add("show")
    setTimeout(function() {
        toast.classList.remove("show")
    }, 2500)
}

// ---- armar html de una card ----

function crearCard(evento, esFavorito) {
    var precio = evento.precio.toLocaleString("es-AR")
    var textoBotonFav = "☆ Favorito"
    var claseBotonFav = "btn btn-fav"

    if (esFavorito) {
        textoBotonFav = "★ Guardado"
        claseBotonFav = "btn btn-fav activo"
    }

    var imagen = obtenerImagenEvento(evento.id)

    var html = ""
    html += '<div class="card">'

    if (imagen != null) {
        html += '<img class="card-imagen" src="' + imagen + '" alt="' + evento.nombre + '">'
    } else {
        html += '<div class="card-color-bar"></div>'
    }

    html += '<div class="card-body">'
    html += '<div class="card-nombre">' + evento.nombre + '</div>'
    html += '<div class="card-info">'
    html += '<span>🎤 ' + evento.artista + '</span>'
    html += '<span>📍 ' + evento.lugar + '</span>'
    html += '</div>'
    html += '<div class="card-precio">$' + precio + '</div>'
    html += '<div class="card-actions">'
    html += '<button class="btn btn-primary" onclick="window.location.href=\'comprar.html?id=' + evento.id + '\'">Comprar</button>'
    html += '<button class="btn btn-ghost" onclick="window.location.href=\'editar.html?id=' + evento.id + '\'">✏️ Editar</button>'

    if (!esFavorito) {
        html += '<button class="btn btn-danger" onclick="eliminarEvento(' + evento.id + ')">🗑️ Eliminar</button>'
    }

    html += '<button class="' + claseBotonFav + '" id="fav-btn-' + evento.id + '" onclick="toggleFavorito(' + evento.id + ', \'' + evento.nombre + '\', \'' + evento.artista + '\', \'' + evento.lugar + '\', ' + evento.precio + ')">' + textoBotonFav + '</button>'
    html += '</div>'
    html += '</div>'
    html += '</div>'

    return html
}

// ---- cargar eventos en index.html ----

async function cargarEventos() {
    var contenedor = document.getElementById("lista-eventos")
    contenedor.innerHTML = "<p style='color:#777'>Cargando...</p>"

    var respuesta = await fetch(urlApi)
    var eventos = await respuesta.json()

    if (eventos.length == 0) {
        contenedor.innerHTML = '<div class="empty-state"><div class="icon">🎵</div><h3>No hay eventos todavía</h3><p>Añadí el primero para empezar</p><a href="agregar.html" class="btn btn-primary btn-large">+ Añadir evento</a></div>'
        return
    }

    var htmlFinal = ""
    for (var i = 0; i < eventos.length; i++) {
        var favorito = estaEnFavoritos(eventos[i].id)
        htmlFinal += crearCard(eventos[i], favorito)
    }

    contenedor.innerHTML = htmlFinal
}

// ---- eliminar evento ----

async function eliminarEvento(id) {
    var confirmar = confirm("¿Seguro que querés eliminar este evento?")
    if (!confirmar) {
        return
    }
    await fetch(urlApi + "/" + id, {
        method: "DELETE"
    })
    mostrarToast("Evento eliminado")
    cargarEventos()
}

// ---- crear evento (agregar.html) ----

async function crearEvento() {
    var nombre = document.getElementById("nombre").value
    var artista = document.getElementById("artista").value
    var lugar = document.getElementById("lugar").value
    var precio = document.getElementById("precio").value
    var archivoImagen = document.getElementById("imagen").files[0]

    if (nombre == "" || artista == "" || lugar == "" || precio == "") {
        mostrarToast("Completa todos los campos")
        return
    }

    var datos = {
        nombre: nombre,
        artista: artista,
        lugar: lugar,
        precio: parseFloat(precio)
    }

    var respuesta = await fetch(urlApi, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(datos)
    })

    var eventoCreado = await respuesta.json()

    if (archivoImagen != null) {
        var lector = new FileReader()
        lector.onload = function() {
            guardarImagenEvento(eventoCreado.id, lector.result)
        }
        lector.readAsDataURL(archivoImagen)
    }

    mostrarToast("Evento creado!")
    setTimeout(function() {
        window.location.href = "index.html"
    }, 1200)
}

// ---- cargar datos al editar (editar.html) ----

async function cargarDatosEdicion() {
    var urlActual = window.location.search
    var params = new URLSearchParams(urlActual)
    var id = params.get("id")

    if (id == null) {
        window.location.href = "index.html"
        return
    }

    var respuesta = await fetch(urlApi + "/" + id)
    var evento = await respuesta.json()

    document.getElementById("nombre").value = evento.nombre
    document.getElementById("artista").value = evento.artista
    document.getElementById("lugar").value = evento.lugar
    document.getElementById("precio").value = evento.precio

    var imagen = obtenerImagenEvento(id)
    var preview = document.getElementById("preview-imagen")
    if (imagen != null && preview != null) {
        preview.src = imagen
        preview.style.display = "block"
    }
}

async function guardarEdicion() {
    var urlActual = window.location.search
    var params = new URLSearchParams(urlActual)
    var id = params.get("id")

    var nombre = document.getElementById("nombre").value
    var artista = document.getElementById("artista").value
    var lugar = document.getElementById("lugar").value
    var precio = document.getElementById("precio").value

    if (nombre == "" || artista == "" || lugar == "" || precio == "") {
        mostrarToast("Completa todos los campos")
        return
    }

    var datos = {
        nombre: nombre,
        artista: artista,
        lugar: lugar,
        precio: parseFloat(precio)
    }

    await fetch(urlApi + "/" + id, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(datos)
    })

    var archivoImagen = document.getElementById("imagen").files[0]
    if (archivoImagen != null) {
        var lector = new FileReader()
        lector.onload = function() {
            guardarImagenEvento(id, lector.result)
        }
        lector.readAsDataURL(archivoImagen)
    }

    mostrarToast("Evento actualizado!")
    setTimeout(function() {
        window.location.href = "index.html"
    }, 1000)
}

// ---- mostrar favoritos (favoritos.html) ----

function mostrarFavoritos() {
    var contenedor = document.getElementById("lista-favoritos")
    if (contenedor == null) {
        return
    }

    var favoritos = obtenerFavoritos()

    if (favoritos.length == 0) {
        contenedor.innerHTML = '<div class="empty-state"><div class="icon">⭐</div><h3>No tenés favoritos guardados</h3><p>Explora los eventos y guarda los que más te gusten</p><a href="index.html" class="btn btn-primary btn-large">Ver eventos</a></div>'
        return
    }

    var htmlFinal = ""
    for (var i = 0; i < favoritos.length; i++) {
        htmlFinal += crearCard(favoritos[i], true)
    }

    contenedor.innerHTML = htmlFinal
}
